import { ChangeEvent, useCallback, useState } from 'react';
import { useDebounce } from 'use-debounce';
import { PublicActionPage } from '@domain/publicActionPage';
import { useGetSmartyAutocomplete } from '@state/addresses/mutations/useGetSmartyAddressAutocomplete';
import { useVerifySmartyAddress } from '@state/addresses/mutations/useVerifySmartyAddress';
import { useGetAccountId } from '@utils/useGetAccountId';
import { SmartyAddress } from './types';

export type UseSmartyAddressInputProps = {
  accountSlug?: string;
  actionPage?: PublicActionPage;
  onChange?: (e: ChangeEvent<HTMLInputElement>) => void;
  onSelectAddress: (address: SmartyAddress) => void;
};

export const useSmartyAddressInput = ({
  accountSlug,
  actionPage,
  onChange,
  onSelectAddress,
}: UseSmartyAddressInputProps) => {
  const [query, setQuery] = useState('');
  const [debouncedQuery] = useDebounce(query, 300);
  const [selected, setSelected] = useState('');
  const [isAddressLoading, setIsAddressLoading] = useState(false);
  const accountId = useGetAccountId();
  const acctSlug = accountSlug ?? accountId ?? actionPage?.account?.slug;

  const { suggestions } = useGetSmartyAutocomplete({
    accountSlug: acctSlug,
    filter: {
      searchTerm: debouncedQuery,
    },
    selected,
  });
  const { error: verifyAddressError, isLoading, verifyAddress } = useVerifySmartyAddress();

  const getFormattedAddress = useCallback((suggestion, isDisplay = false) => {
    let secondary = suggestion.secondary ?? '';
    if (secondary) {
      if ((suggestion?.entries ?? 0) > 1) {
        // Add the word "entries" to the parentheses in the UI for user-friendliness.
        secondary += ` (${suggestion.entries}${isDisplay ? ' entries' : ''})`;
      }
    }

    return [
      suggestion.street_line,
      secondary,
      suggestion.city,
      suggestion.state,
      suggestion.zipcode,
    ].join(' ');
  }, []);

  const handleChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      setSelected('');
      setQuery(e.target.value);
      onChange?.(e);
    },
    [onChange]
  );

  const handleSelectAddress = useCallback(
    (suggestion) => {
      setQuery(`${suggestion.street_line} ${suggestion.secondary}`);
      onChange?.({
        target: {
          value: `${suggestion?.street_line} ${suggestion?.secondary}`,
        },
      } as ChangeEvent<HTMLInputElement>);

      if (suggestion.entries > 1) {
        setIsAddressLoading(true);

        // Add a small, barely perceptible delay before resetting the suggestions to allow
        // mobile users time to lift their finger before the next set of results displays.
        // Fixes an issue where the next set of results would load with the index of
        // whereever the user tapped highlighted/active.
        setTimeout(() => {
          setSelected(getFormattedAddress(suggestion));
          setIsAddressLoading(false);
        }, 150);
      } else {
        setQuery('');
        setSelected('');
        verifyAddress({ accountSlug: acctSlug, address: suggestion });
        onSelectAddress(suggestion);
      }
    },
    [acctSlug, getFormattedAddress, onChange, onSelectAddress, verifyAddress]
  );

  return {
    getFormattedAddress,
    handleChange,
    handleSelectAddress,
    isAddressLoading: isAddressLoading || isLoading,
    query,
    suggestions: suggestions?.slice(0, 5) ?? [],
    verifyAddressError,
  };
};
