import { useQuery } from 'react-query';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { SmartyAddress } from '@ui/components/formControls/compositions/SmartyAddressInput/types';
import { makeSearchParams } from '@utils';

type UseGetSmartyAutocompleteProps = {
  accountSlug?: string;
  filter: {
    searchTerm: string;
  };
  /**
   * The `selected` parameter is used for addresses with multiple entries,
   * e.g. apartment buildings.
   * https://www.smarty.com/docs/cloud/us-autocomplete-pro-api#pro-secondary-expansion
   */
  selected?: string;
};

export const useGetSmartyAutocomplete = ({
  accountSlug,
  filter,
  selected,
}: UseGetSmartyAutocompleteProps) => {
  const params = makeSearchParams({
    accountSlug,
    q: filter?.searchTerm,
    selected,
  });

  const query = useQuery<SmartyAddress[], IErrorResponse>(
    generateQueryKey({
      parameters: params.raw,
      resourceId: filter?.searchTerm,
      resourceKey: resourceKeys.smartyAddressAutocomplete,
    }),
    () => {
      if (!filter?.searchTerm || !accountSlug) {
        return [];
      }

      return new ApiClient({ namespace: 'public' }).get<SmartyAddress[]>(
        `/smarty/autocomplete?${params.toString()}`
      );
    },
    {
      enabled: !!filter?.searchTerm,
    }
  );

  return {
    error: query.error,
    isError: query.isError,
    isLoading: query.isLoading,
    suggestions: query.data,
  };
};
